import json
from typing import Dict, Any, List

class UserRepository:
    """Manages user data persistence and retrieval."""
    def __init__(self):
        self._users: Dict[str, str] = {} # email -> name

    def add_user(self, name: str, email: str) -> bool:
        """Adds a new user if the email does not already exist."""
        if email in self._users:
            return False
        self._users[email] = name
        print(f"User {name} added with email {email}")
        return True

    def get_user(self, email: str) -> str | None:
        """Retrieves the user name by email."""
        return self._users.get(email)

class UserStore:
    """Handles loading and saving of users to a database file."""
    def __init__(self, db_path: str):
        self.db_path = db_path
        self._data: Dict[str, Any] = {} # structure to hold all user data

    def save(self, users: List[dict]):
        """Saves the list of user dictionaries to the store."""
        # Assuming 'users' is a list of dicts like [{'email': 'e1', 'name': 'n1'}, ...]
        self._data['users'] = {user['email']: user['name'] for user in users}
        with open(self.db_path, 'w') as f:
            json.dump({"users": self._data['users']}, f)

    def load(self) -> Dict[str, str]:
        """Loads stored user data from the database file."""
        try:
            with open(self.db_path, 'r') as f:
                data = json.load(f)
                return data.get('users', {})
        except FileNotFoundError:
            print("Database file not found. Returning empty user store.")
            return {}

class EmailService:
    """Handles sending various email notifications."""
    # Mocking external service calls
    def send_welcome_email(self, email: str) -> bool:
        print(f"--- EMAIL SERVICE ---")
        print(f"Simulating welcome email sent successfully to {email}.")
        return True

    def send_reset_email(self, email: str) -> bool:
        print(f"--- EMAIL SERVICE ---")
        print(f"Simulating password reset link sent successfully to {email}. Check your inbox!")
        return True

# Example usage (optional, but good for validation context):
